import groupBy from "object.groupby";
import invariant from "tiny-invariant";
import { additionalContext } from "../../../Client.js";
import { ObjectDefRef } from "../../../object/convertWireToOsdkObjects/InternalSymbols.js";
import { ListQuery, PIVOT_IDX, RDP_IDX, RIDS_IDX } from "./ListQuery.js";
export class InterfaceListQuery extends ListQuery {
  createObjectSet(store) {
    const rdpConfig = this.cacheKey.otherKeys[RDP_IDX];
    const pivotInfo = this.cacheKey.otherKeys[PIVOT_IDX];
    const rids = this.cacheKey.otherKeys[RIDS_IDX];
    if (pivotInfo != null) {
      const sourceSet = createSourceSetForPivot(store, pivotInfo, rids);
      let objectSet = sourceSet.where(this.canonicalWhere).pivotTo(pivotInfo.linkName);
      if (rdpConfig != null) {
        objectSet = objectSet.withProperties(rdpConfig);
      }

      // intersectWith for pivot queries is deferred to fetchPageData
      // where the target type can be resolved asynchronously
      return objectSet;
    }
    const type = "interface";
    const objectTypeDef = {
      type,
      apiName: this.apiName
    };
    const clientCtx = store.client[additionalContext];
    let objectSet;
    if (rids != null) {
      objectSet = clientCtx.objectSetFactory(objectTypeDef, clientCtx, {
        type: "static",
        objects: [...rids]
      });
    } else {
      objectSet = store.client(objectTypeDef);
    }
    if (rdpConfig != null) {
      objectSet = objectSet.withProperties(rdpConfig);
    }
    return objectSet.where(this.canonicalWhere);
  }
  async revalidateObjectType(apiName) {
    const objectMetadata = await this.store.client.fetchMetadata({
      type: "object",
      apiName
    });
    if (this.apiName in objectMetadata.interfaceMap) {
      await this.revalidate(/* force */true);
    }
  }
  async postProcessFetchedData(data) {
    return reloadDataAsFullObjects(this.store.client, data);
  }
  createPayload(params) {
    const resolvedList = params.resolvedData.map(obj => obj.$as(this.apiName));
    return {
      resolvedList,
      isOptimistic: params.isOptimistic,
      fetchMore: this.fetchMore,
      hasMore: this.nextPageToken != null,
      status: params.status,
      lastUpdated: params.lastUpdated
    };
  }
  extractRelevantObjects(changes) {
    const matchesApiName = ([, object]) => {
      return this.apiName in object[ObjectDefRef].interfaceMap;
    };
    const added = Array.from(changes.addedObjects).filter(matchesApiName).map(([, object]) => object.$as(this.apiName));
    const modified = Array.from(changes.modifiedObjects).filter(matchesApiName).map(([, object]) => object.$as(this.apiName));
    return {
      added: {
        all: added,
        strictMatches: new Set(),
        sortaMatches: new Set()
      },
      modified: {
        all: modified,
        strictMatches: new Set(),
        sortaMatches: new Set()
      }
    };
  }
}
function createSourceSetForPivot(store, pivotInfo, rids) {
  const clientCtx = store.client[additionalContext];
  if (rids != null) {
    return clientCtx.objectSetFactory({
      type: "object",
      apiName: pivotInfo.sourceType
    }, clientCtx, {
      type: "static",
      objects: [...rids]
    });
  }
  if (pivotInfo.sourceTypeKind === "interface") {
    return store.client({
      type: "interface",
      apiName: pivotInfo.sourceType
    });
  }
  return store.client({
    type: "object",
    apiName: pivotInfo.sourceType
  });
}

// Hopefully this can go away when we can just request the full object properties on first load
async function reloadDataAsFullObjects(client, data) {
  if (data.length === 0) {
    return data;
  }
  const groups = groupBy(data, x => x.$objectType);
  const objectTypeToPrimaryKeyToObject = Object.fromEntries(await Promise.all(Object.entries(groups).map(async ([apiName, objects]) => {
    // Interface query results don't have ObjectDefRef, so we fetch metadata to get primaryKeyApiName
    const objectDef = await client.fetchMetadata({
      type: "object",
      apiName
    });
    const where = {
      [objectDef.primaryKeyApiName]: {
        $in: objects.map(x => x.$primaryKey)
      }
    };
    const result = await client(objectDef).where(where).fetchPage({
      $includeRid: true
    });
    return [apiName, Object.fromEntries(result.data.map(x => [x.$primaryKey, x]))];
  })));
  return data.map(obj => {
    const fullObject = objectTypeToPrimaryKeyToObject[obj.$objectType][obj.$primaryKey];
    !fullObject ? process.env.NODE_ENV !== "production" ? invariant(false, `Could not find object ${obj.$objectType} ${obj.$primaryKey}`) : invariant(false) : void 0;
    return fullObject;
  });
}